// Aggregate all test results from all pipelines
const allResults = {
  pipelineId: `report-${Date.now()}`,
  timestamp: new Date().toISOString(),
  unitTests: $('Parse Unit Test Results').first()?.json || {},
  integrationTests: $('AI Integration Result Analysis').first()?.json || {},
  uiTests: $('AI UI Test Result Analysis').first()?.json || {},
  nfrTests: $('AI NFR Performance Analysis').first()?.json || {},
  aiAnalysis: $('Parse AI Analysis').first()?.json?.analysis || {}
};

// Calculate overall health score
const scores = [];
if (allResults.unitTests.passRate) scores.push(parseFloat(allResults.unitTests.passRate));
if (allResults.aiAnalysis.qualityScore) scores.push(allResults.aiAnalysis.qualityScore);

allResults.overallHealthScore = scores.length > 0 ?
  (scores.reduce((a, b) => a + b, 0) / scores.length).toFixed(2) : 'N/A';

allResults.overallStatus = 
  allResults.unitTests.status === 'FAILED' || 
  allResults.integrationTests.status === 'FAILED' ? 'FAILED' : 'PASSED';

return [{ json: allResults }];

